 1	import React, { FC } from 'react';
 2	
 3	import { Modal, Title } from '@patternfly/react-core';
 4	import { NodeNetworkConfigurationInterface } from '@types';
 5	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
 6	
 7	import { InterfaceDrawerTabId, InterfaceDrawerTabProps } from './constants';
 8	import InterfaceDrawerDetailsTab from './InterfaceDrawerDetailsTab';
 9	import InterfaceDrawerYAMLFooter from './InterfaceDrawerFooter';
10	import InterfaceDrawerYAMLTab from './InterfaceDrawerYAMLTab';
11	
12	type InterfaceDrawerProps = {
13	  selectedInterface: NodeNetworkConfigurationInterface;
14	  onClose: () => void;
15	};
16	
17	const InterfaceDrawer: FC<InterfaceDrawerProps> = ({ selectedInterface, onClose }) => {
18	  const { t } = useNMStateTranslation();
19	
20	  const Tabs: InterfaceDrawerTabProps[] = [
21	    {
22	      title: t('Details'),
23	      id: 'drawer-details',
24	      component: InterfaceDrawerDetailsTab,
25	    },
26	    {
27	      title: t('YAML'),
28	      id: 'drawer-yaml',
29	      component: InterfaceDrawerYAMLTab,
30	    },
31	  ];
32	
33	  const selectedTab = (location.hash.replace('#', '') as InterfaceDrawerTabId) || Tabs?.[0]?.id;
34	
35	  const SelectedTabComponent =
36	    Tabs.find((tab) => tab.id === selectedTab)?.component ?? Tabs?.[0]?.component;
37	
38	  return (
39	    <Modal
40	      aria-label="Interface drawer"
41	      className="ocs-modal co-catalog-page__overlay co-catalog-page__overlay--right interface-drawer"
42	      isOpen={!!selectedInterface}
43	      onClose={onClose}
44	      disableFocusTrap
45	      header={<Title headingLevel="h2">{selectedInterface?.name}</Title>}
46	      data-test="interface-drawer"
47	      footer={
48	        selectedTab === 'drawer-yaml' && (
49	          <InterfaceDrawerYAMLFooter selectedInterface={selectedInterface} />
50	        )
51	      }
52	    >
53	      <div className="co-m-horizontal-nav pf-u-px-md">
54	        <ul className="co-m-horizontal-nav__menu">
55	          {Tabs.map((tab) => (
56	            <li
57	              key={tab.id}
58	              className={`co-m-horizontal-nav__menu-item ${
59	                selectedTab === tab.id ? 'co-m-horizontal-nav-item--active' : ''
60	              }`}
61	              data-test={`horizontal-tab-${tab.id}`}
62	            >
63	              <a
64	                data-test-id="horizontal-link-Details"
65	                href={`${location.pathname}${location.search}#${tab.id}`}
66	              >
67	                {tab.title}
68	              </a>
69	            </li>
70	          ))}
71	        </ul>
72	      </div>
73	      <div className="pf-u-p-xl">
74	        <SelectedTabComponent selectedInterface={selectedInterface} />
75	      </div>
76	    </Modal>
77	  );
78	};
79	
80	export default InterfaceDrawer;

